using System.ComponentModel;
using System.Net.Http.Json;
using System.Text.Json.Serialization;
using ModelContextProtocol.Server;

namespace McpToolsDemo;

/// <summary>
/// MCP tool class wrapping the Open-Meteo weather API.
/// The SDK discovers tools by scanning for [McpServerToolType] classes
/// and [McpServerTool] methods. Constructor parameters are resolved via DI.
/// </summary>
[McpServerToolType]
public class WeatherTools
{
    private readonly HttpClient _httpClient;

    // The SDK resolves this via DI — see Program.cs where AddHttpClient is registered.
    public WeatherTools(HttpClient httpClient)
    {
        _httpClient = httpClient;
    }

    [McpServerTool, Description("Get current weather for a location by latitude and longitude.")]
    public async Task<string> GetCurrentWeather(
        [Description("Latitude of the location")] double latitude,
        [Description("Longitude of the location")] double longitude,
        CancellationToken cancellationToken = default)
    {
        var url = $"https://api.open-meteo.com/v1/forecast?latitude={latitude}&longitude={longitude}"
                + "&current=temperature_2m,wind_speed_10m&temperature_unit=fahrenheit&wind_speed_unit=mph";

        var response = await _httpClient.GetFromJsonAsync<WeatherResponse>(url, cancellationToken);

        if (response?.Current is null)
            return "Unable to retrieve weather data.";

        return $"Temperature: {response.Current.Temperature}°F, "
             + $"Wind speed: {response.Current.WindSpeed} mph";
    }

    [McpServerTool, Description("Look up coordinates for a city name.")]
    public async Task<string> GeolocateCity(
        [Description("City name to search for")] string city,
        CancellationToken cancellationToken = default)
    {
        var url = $"https://geocoding-api.open-meteo.com/v1/search?name={Uri.EscapeDataString(city)}&count=1";
        var response = await _httpClient.GetFromJsonAsync<GeoResponse>(url, cancellationToken);

        if (response?.Results is not { Count: > 0 })
            return $"Could not find coordinates for '{city}'.";

        var loc = response.Results[0];
        return $"{loc.Name}: latitude={loc.Latitude}, longitude={loc.Longitude}";
    }
}

// --- DTOs for Open-Meteo responses ---

public record WeatherResponse(
    [property: JsonPropertyName("current")] CurrentWeather? Current);

public record CurrentWeather(
    [property: JsonPropertyName("temperature_2m")] double Temperature,
    [property: JsonPropertyName("wind_speed_10m")] double WindSpeed);

public record GeoResponse(
    [property: JsonPropertyName("results")] List<GeoResult>? Results);

public record GeoResult(
    [property: JsonPropertyName("name")] string Name,
    [property: JsonPropertyName("latitude")] double Latitude,
    [property: JsonPropertyName("longitude")] double Longitude);

